+            state.leak_timeout_secs = leak_timeout_secs;
+        });
+        tracker
+    }
+
+    /// Create a tracker with a custom per-flow budget. INV-OBL-BUDGET-BOUND
+    pub fn with_flow_budget(flow_budget: usize) -> Self {
